setupScript:
(function () {
  return (async function () {
    try {
      var ajaxUrl = (window.AMAN_CATEGORIES && window.AMAN_CATEGORIES.ajax_url) || '/wp-admin/admin-ajax.php';
      var body = new URLSearchParams();
      body.append('action', 'data_fetch');
      body.append('s', '');
      var r = await fetch(ajaxUrl, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8',
          'X-Requested-With': 'XMLHttpRequest'
        },
        credentials: 'same-origin',
        body: body.toString()
      });
      if (!r.ok) return -2;
      var data = await r.json();
      if (!data || !data.applications) return -3;
      var inner = document.querySelector('.positions_page__content-applications-inner');
      if (inner) {
        inner.outerHTML = data.applications;
      } else {
        var section = document.querySelector('.positions_page__content-applications');
        if (section) section.innerHTML = data.applications;
        else return -4;
      }
      return document.querySelectorAll('article.positions_page__application').length;
    } catch (e) { return -1; }
  })();
})();
